using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1) GetTypeInfo<T>(): strongly-typed metadata retrieval ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> returned type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// --- 2) TryGetTypeInfo<T>(): check-without-throwing ---

// 2a) With the default (reflection-based) resolver every type resolves:
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded – type: {info!.Type.Name}");
}

// 2b) Use a resolver that only knows about Person, so probing for
//     an unknown type returns false instead of throwing.
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver
    {
        Modifiers =
        {
            static ti =>
            {
                // Reject every type except Person
                if (ti.Type != typeof(Person))
                    throw new NotSupportedException($"{ti.Type.Name} not supported");
            }
        }
    }
};

if (limited.TryGetTypeInfo<int>(out JsonTypeInfo<int>? intInfo))
{
    Console.WriteLine($"Unexpected: got type info for Int32");
}
else
{
    Console.WriteLine("TryGetTypeInfo<int> returned false – no metadata available (no exception thrown)");
}

public record Person(string Name, int Age);

